import { styled } from 'styled-components';

import { Icon } from '#components/Icon';

import * as device from '#theme/devices';

export const StyledButton = styled.a`
  width: 32px;
  color: ${({ theme, type }) =>
    type && theme.color.social[type]?.base
      ? theme.color.social[type].base
      : theme.color.actionBrand.base};

  @media ${device.tablet} {
    &.mobile-only {
      display: none;
    }
  }

  &:hover {
    color: ${({ theme, type }) =>
      type && theme.color.social[type]?.alt
        ? theme.color.social[type].alt
        : theme.color.actionBrand.alt};
  }
`;

export const StyledIcon = styled(Icon)``;
